def _match_keyword(text: str, keyword: str) -> bool:
    """三层匹配：精确 -> jieba分词 -> 字级"""
    if keyword in text:
        return True
    text_words = list(jieba.cut(text))
    kw_words = list(jieba.cut(keyword))
    # 简化版子序列匹配
    if len(kw_words) == 1:
        return kw_words[0] in text_words
    try:
        idx = text_words.index(kw_words[0])
        for kw in kw_words[1:]:
            found = False
            for i in range(idx+1, min(idx+4, len(text_words))):
                if text_words[i] == kw:
                    idx = i
                    found = True
                    break
            if not found:
                return False
        return True
    except:
        pass
    # 字级兜底
    return bool(re.search(".".join(keyword), text))

def _check_excluded(text: str):
    """
    检查是否命中全局排除词
    返回: (是否被排除, 命中的排除词)
    """
    if not text:
        return False, None
    text_lower = text.lower()
    for excluded_word in EXCLUDED_WORDS:
        if _match_keyword(text_lower, excluded_word):
            return True, excluded_word
    return False, None

def check_excluded(text: str):
    """供外部调用的排除词检测接口"""
    return _check_excluded(text)

def calculate_confidence(text: str, category: str) -> dict:
    """智能软过滤：排除词扣分博弈制"""
    text_lower = text.lower()
    words = set(jieba.lcut(text_lower))
    
    cat_data = KEYWORDS_DB.get(category, {})
    
    # 正向得分
    score = 0
    matched_keywords = []
    
    core_words = set(cat_data.get("core", []))
    feature_words = set(cat_data.get("feature", []))
    
    # 核心词+3
    for kw in core_words:
        if kw in text_lower or kw in words:
            score += 3
            matched_keywords.append(f"{kw}(核)")
    
    # 特征词+1
    for kw in feature_words:
        if kw in text_lower or kw in words:
            score += 1
            matched_keywords.append(f"{kw}(特)")
    
    # 负向扣分（关键改进）
    exclude_hits = words & EXCLUDE_WORDS
    exclude_penalty = len(exclude_hits) * 2  # 每个排除词扣2分
    
    # 净得分计算
    net_score = score - exclude_penalty
    
    # 返回详细结果供UI展示
    return {
        "raw_score": score,              # 原始得分
        "exclude_penalty": exclude_penalty,  # 排除词扣分
        "net_score": net_score,          # 净得分（用于判定）
        "keywords": matched_keywords,
        "exclude_hits": list(exclude_hits),  # 命中的排除词（用于提示）
        "is_excluded": net_score < 3     # 只有净分<3才视为排除
    }


def keyword_match(text: str) -> tuple:
    """返回最佳类别和详细信息（供UI展示排除词处理过程）"""
    if not text:
        return None, {}
    
    best_cat = None
    best_result = None
    best_net_score = -999
    
    for cat in KEYWORDS_DB.keys():
        result = calculate_confidence(text, cat)
        # 使用净得分比较
        if result["net_score"] > best_net_score:
            best_net_score = result["net_score"]
            best_cat = cat
            best_result = result
    
    # 净得分<3才返回None（硬过滤阈值）
    if best_net_score < 3:
        return None, best_result
    
    return best_cat, best_result
